```csharp
// In the export orchestration service (NOT a workflow)
var handle = await client.StartActivityAsync(
    () => MyActivities.ExportDataAsync(new ExportInput(userId)),
    new("export-" + userId, "export-task-queue")
    {
        ScheduleToCloseTimeout = TimeSpan.FromMinutes(10),
