[Activity]
public static async Task<string> ExportDataAsync(ExportInput input)
{
    var token = ActivityExecutionContext.Current.Info.TaskToken;
    await _notificationService.RegisterCallbackAsync(input.UserId, token);
    throw new CompleteAsyncException(); // signal async completion
}

// In the S3 polling service:
var asyncHandle = client.GetAsyncActivityHandle(capturedToken);
